  "business_expectations": [
    {
      "expectation_id": "意图识别结果应为客户画像",
      "downstream_consumer": "营销规划引擎",
      "user_intent": "查看上季度购买重疾险的客户特征",
      "expected_outcome": "意图标签为 customer_portrait，且置信度较高",
      "required_capabilities": [
        "NLU",
        "意图分类",
        "实体抽取"
      ],
