        "intent 字段等于 customer_portrait 或 intent_name 包含客户画像",
        "confidence ≥ 0.8"
      ],
      "boundary": {
        "excludes": [
          "多轮交互",
          "卡片生成"
        ]
      },
      "priority": "最高",
      "evidence_refs": []
    },
    {
      "expectation_id": "关键实体目标产品提取",
      "downstream_consumer": "营销规划引擎",
      "user_intent": "指定了重疾险产品",
      "expected_outcome": "target_value 字段值为重疾险",
      "required_capabilities": [
        "实体识别"
      ],
      "acceptance_criteria": [
        "target_value 为 重疾险"
      ],
      "boundary": {},
      "priority": "高",
      "evidence_refs": []
    },
    {
      "expectation_id": "置信度符合预期",
      "downstream_consumer": "营销规划引擎",
      "user_intent": "需要可靠意图判断",
      "expected_outcome": "confidence ≥ 0.95，或至少 ≥ 0.8",
      "required_capabilities": [
        "置信度计算"
      ],
      "acceptance_criteria": [
        "confidence 数值 ≥ 0.95"
      ],
      "boundary": {},
      "priority": "高",
      "evidence_refs": []
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "意图识别结果应为客户画像",
      "status": "not_fulfilled",
      "score": 0,
      "expected_evidence": [
        "intent: customer_portrait"
      ],
      "actual_evidence": [
        "intent: other",
        "subIntent: 其他意图"
      ],
      "downstream_impact": "后续规划流程无法启动客户画像分析，需人工接管",
      "blocking": true,
      "confidence": 1.0,
      "evidence_refs": []
    },
    {
      "expectation_id": "关键实体目标产品提取",
      "status": "not_fulfilled",
      "score": 0,
      "expected_evidence": [
        "target_value: 重疾险"
      ],
      "actual_evidence": [
        "target_value: null"
      ],
      "downstream_impact": "无法定位具体产品维度，画像分析缺少核心筛选条件",
      "blocking": true,
      "confidence": 0.95,
      "evidence_refs": []
    },
    {
      "expectation_id": "置信度符合预期",
      "status": "not_fulfilled",
      "score": 0,
      "expected_evidence": [
        "confidence: 0.95"
      ],
      "actual_evidence": [
        "confidence: 0.5"
      ],
      "downstream_impact": "低置信度导致下游可能降级或提示用户二次确认，影响自动化程度",
      "blocking": false,
      "confidence": 1.0,
      "evidence_refs": []
    }
  ],
  "overall_fulfillment": {
    "status": "not_fulfilled",
    "reason": "意图识别错误，未提取目标产品，置信度远低于预期"
  },
  "expected": {
    "intent": "customer_portrait",
    "confidence": 0.95,
    "target_value": "重疾险"
  },
  "missing": [
    {
      "kind": "intent",
      "error_type": "misclassification",
      "expected": "customer_portrait",
      "actual": "other",
      "evidence_ref": "extracted_output",
      "raw": {
        "intent": "other"
      },
      "incomplete": false
    },
    {
      "kind": "entity",
      "error_type": "missing_entity",
      "expected": "重疾险",
      "actual": null,
      "evidence_ref": "extracted_output",
      "raw": {
        "target_value": null
      },
      "incomplete": true
    }
  ],
  "wrong": [
    {
      "kind": "intent",
      "error_type": "incorrect_label",
      "expected": "customer_portrait",
      "actual": "other",
      "evidence_ref": "extracted_output",
      "raw": {
        "intent": "other"
      },
      "incomplete": false
    }
  ],
  "extra": [],
  "evidence": [
    {
      "source": "raw_response",
      "intent": "other",
      "confidence": 0.5,
      "target_value": null
    }
  ],
  "reasoning_summary": "用户查询意图明确为客户画像，并指定了产品重疾险和时间维度。然而实际识别结果将意图误判为“其他意图”，且未提取任何目标产品实体，置信度仅为0.5，远低于预期0.95。所有关键预期均未满足，整体评估为 not_fulfilled。"
}

